
.fur-workbench {
  box-sizing: border-box;
  width: 100%;
  color: #221f1b;
  font-family: Georgia, 'Times New Roman', serif;
  background:
    linear-gradient(135deg, rgba(245, 239, 225, 0.96), rgba(225, 232, 220, 0.94)),
    repeating-linear-gradient(90deg, rgba(47, 43, 35, 0.05) 0 1px, transparent 1px 18px);
  border: 1px solid rgba(68, 55, 39, 0.22);
  border-radius: 8px;
  padding: 16px;
}

.mast {
  display: flex;
  align-items: end;
  justify-content: space-between;
  gap: 14px;
  padding-bottom: 12px;
  border-bottom: 1px solid rgba(68, 55, 39, 0.18);

  h1 {
    margin: 2px 0 0;
    font-size: 28px;
    line-height: 1.1;
    letter-spacing: 0;
  }
}

.mast-controls {
  display: grid;
  justify-items: end;
  gap: 8px;
}

.kicker {
  margin: 0;
  color: #666c48;
  font: 700 11px/1.2 Verdana, sans-serif;
  letter-spacing: 0;
  text-transform: uppercase;
}

button {
  border-radius: 6px;
  cursor: pointer;
}

.mode-strip {
  display: grid;
  grid-template-columns: repeat(2, minmax(54px, 1fr));
  gap: 6px;
}

.worldbook-toggle {
  display: flex;
  align-items: center;
  gap: 7px;
  color: #253d34;
  font: 700 12px/1.2 Verdana, sans-serif;

  input {
    width: 15px;
    height: 15px;
    margin: 0;
    accent-color: #253d34;
  }
}

.mode-strip button,
.stage-tabs button,
.preset-shelf button {
  border: 1px solid rgba(58, 48, 34, 0.2);
  background: rgba(255, 255, 255, 0.55);
  color: #4a3c2f;
  font: 700 12px/1 Verdana, sans-serif;
  padding: 10px 8px;
}

.mode-strip .active,
.stage-tabs .active {
  background: #253d34;
  color: #f7f0df;
  border-color: #253d34;
}

.stage-tabs .done:not(.active) {
  border-color: rgba(55, 102, 71, 0.38);
  background: rgba(75, 126, 89, 0.13);
}

.workspace {
  display: grid;
  grid-template-columns: minmax(0, 1.05fr) minmax(300px, 0.95fr);
  gap: 14px;
  padding-top: 14px;
}

.input-panel,
.preview-panel {
  background: rgba(255, 252, 244, 0.64);
  border: 1px solid rgba(68, 55, 39, 0.16);
  border-radius: 8px;
  padding: 13px;
}

.input-panel,
.page-body,
.preview-panel {
  display: grid;
  gap: 12px;
}

.preview-panel {
  align-self: start;
  max-height: min(78vh, 760px);
  min-height: 0;
  overflow-y: auto;
  overscroll-behavior: contain;
}

.stage-tabs {
  display: grid;
  grid-template-columns: repeat(7, minmax(0, 1fr));
  gap: 6px;

  button {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 5px;
  }

  span {
    opacity: 0.65;
    font-size: 10px;
  }
}

.preset-shelf {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 8px;

  button {
    display: grid;
    gap: 5px;
    min-height: 58px;
    text-align: left;
  }

  span {
    opacity: 0.72;
    font-size: 10px;
    text-transform: uppercase;
  }

  strong {
    font-size: 13px;
    line-height: 1.25;
  }
}

.field-grid,
.status-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

label {
  display: grid;
  gap: 6px;
  color: #5b4a38;
  font: 700 12px/1.2 Verdana, sans-serif;
}

input,
select,
textarea {
  box-sizing: border-box;
  width: 100%;
  border: 1px solid rgba(61, 50, 36, 0.2);
  border-radius: 6px;
  background: rgba(255, 255, 255, 0.76);
  color: #231f1a;
  font: 14px/1.45 'Trebuchet MS', Verdana, sans-serif;
  padding: 10px 11px;
}

textarea {
  resize: vertical;
}

.actions {
  display: flex;
  gap: 8px;
  justify-content: flex-end;
}

.saved-list {
  display: grid;
  gap: 8px;
  border: 1px solid rgba(55, 67, 50, 0.16);
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.46);
  padding: 10px;
}

.saved-list-head,
.saved-list article {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
}

.saved-list-head {
  color: #253d34;
  font: 700 12px/1.2 Verdana, sans-serif;

  span {
    color: #6b6f4c;
    font-size: 11px;
  }
}

.saved-list article {
  border-top: 1px solid rgba(58, 48, 34, 0.12);
  padding-top: 8px;

  strong {
    min-width: 0;
    color: #2f2b26;
    font: 700 13px/1.35 Verdana, sans-serif;
    overflow-wrap: anywhere;
  }
}

.primary,
.secondary {
  border-radius: 6px;
  cursor: pointer;
  font: 700 13px/1 Verdana, sans-serif;
  padding: 11px 14px;
}

.primary {
  border: 1px solid #253d34;
  background: #253d34;
  color: #fff9ea;
}

.primary:disabled {
  cursor: wait;
  opacity: 0.55;
}

.secondary {
  border: 1px solid rgba(58, 48, 34, 0.24);
  background: rgba(255, 255, 255, 0.62);
  color: #2f2b26;
}

.preview-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;

  strong {
    color: #253d34;
    font: 700 13px/1 Verdana, sans-serif;
  }
}

.compact {
  padding: 8px 10px;
  font-size: 12px;
}

.status-grid div,
.missing-list,
.notice {
  border-radius: 8px;
  padding: 10px;
}

.status-grid div {
  display: grid;
  gap: 4px;
  border: 1px solid rgba(55, 67, 50, 0.16);
  background: rgba(255, 255, 255, 0.5);
}

.status-grid span {
  color: #6b6f4c;
  font: 700 10px/1 Verdana, sans-serif;
}

.status-grid strong {
  color: #2f2b26;
  font: 700 12px/1.3 Verdana, sans-serif;
}

pre {
  box-sizing: border-box;
  width: 100%;
  max-width: 100%;
  margin: 0;
  white-space: pre-wrap;
  word-break: break-word;
  border-radius: 8px;
  background: #1f2822;
  color: #f4ead6;
  font: 13px/1.55 Consolas, 'Courier New', monospace;
  padding: 14px;
}

.missing-list {
  display: flex;
  gap: 8px;
  background: rgba(128, 88, 52, 0.12);
  color: #684222;
  font: 13px/1.4 Verdana, sans-serif;
}

.notice {
  display: grid;
  gap: 4px;
  font-family: Verdana, sans-serif;

  strong {
    font-size: 13px;
  }

  span {
    font-size: 12px;
    line-height: 1.5;
  }
}

.notice-calm {
  background: rgba(67, 102, 85, 0.12);
  color: #253d34;
}

.notice-hot {
  background: rgba(128, 58, 52, 0.13);
  color: #6c2d29;
}

.notice-worldbook {
  background: rgba(61, 77, 115, 0.12);
  color: #263757;
}

@media (max-width: 860px) {

  .workspace,
  .field-grid,
  .status-grid,
  .preset-shelf {
    grid-template-columns: 1fr;
  }

  .mast {
    display: grid;
    align-items: start;
  }

  .mast-controls {
    justify-items: stretch;
  }

  .stage-tabs {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}
